    fontSize: '14px',
    boxSizing: 'border-box'
  },
  usersList: {
    flex: 1,
    overflowY: 'auto',
    borderTop: '1px solid #eee'
  },
  userItem: {
    padding: '12px',
    borderBottom: '1px solid #eee',
    cursor: 'pointer',
    transition: 'all 0.3s ease',
  },
  userInfo: {
    display: 'flex',
    flexDirection: 'column',
    gap: '5px'
  },
  userName: {
    fontWeight: '600',
    fontSize: '14px',
    color: '#333'
  },
  userEmail: {
    fontSize: '12px',
    color: '#666'
  },
  userRole: {
    display: 'flex',
    gap: '8px'
  },
  roleBadge: {
    padding: '2px 8px',
    borderRadius: '4px',
    color: '#fff',
    fontSize: '11px',
    fontWeight: '500',
    width: 'fit-content'
  },
  userDetailsCard: {
    backgroundColor: '#f9f9f9',
    padding: '15px',
    borderRadius: '4px',
    marginBottom: '20px',
    borderLeft: '4px solid #2196F3'
  },
  detailRow: {
    display: 'flex',
    justifyContent: 'space-between',
    padding: '8px 0',
    borderBottom: '1px solid #eee',
    fontSize: '14px'
  },
  detailLabel: {
    fontWeight: '600',
    color: '#666',
    minWidth: '120px'
  },
  logsTable: {
    flex: 1,
    overflowY: 'auto'
  },
  table: {
    width: '100%',
    borderCollapse: 'collapse',
    marginTop: '10px'
  },
  tableHeader: {
    backgroundColor: '#f5f5f5',
    position: 'sticky',
    top: 0,
    zIndex: 1
  },
  th: {
    padding: '12px',
    textAlign: 'left',
    fontWeight: '600',
    fontSize: '13px',
    color: '#333',
    borderBottom: '2px solid #ddd'
  },
  tableRow: {
    borderBottom: '1px solid #eee',
    transition: 'background-color 0.2s'
  },
  td: {
    padding: '12px',
    fontSize: '13px',
    color: '#555'
  },
  ipBadge: {
    backgroundColor: '#e8f5e9',
    padding: '2px 6px',
    borderRadius: '3px',
    fontSize: '12px',
    fontFamily: 'monospace',
    color: '#2e7d32'
  },
  missingBadge: {
    backgroundColor: '#fff3cd',
    color: '#8a6d3b',
    padding: '2px 6px',
    borderRadius: '3px',
    fontSize: '12px',
    fontWeight: '500'
  },
  emptyState: {
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
    justifyContent: 'center',
    flex: 1,
    color: '#999'
  },
  emptyIcon: {
    fontSize: '48px',
    marginBottom: '10px'
  },
  emptyText: {
    fontSize: '16px'
  },
  loadingText: {
    textAlign: 'center',
    padding: '20px',
    color: '#999'
  },
  noData: {
    textAlign: 'center',
    padding: '20px',
    color: '#999'
  },
  errorMessage: {
    backgroundColor: '#ffebee',
    color: '#c62828',
    padding: '12px',
    borderRadius: '4px',
    marginTop: '10px',
    fontSize: '14px'
  }
};

export default AdminUserLoginHistory;
